import { describe, expect, it } from 'vitest';

import {
  MCKAY_C1,
  MCKAY_C2,
  MCKAY_CHI1,
  MCKAY_CHI2,
  MCKAY_CHI3,
  PleromaticMonsterMeshMaster,
  TRITON_ROTATION_ORDER,
  clinamenAppearsInMckayC1,
  clinamenAtC1,
  clinamenAtC2,
  forkChildrenConstructiveInterference,
  interferencePatternIsPureCoincidence,
  mckayC1Decomposition,
  mckayC2Decomposition,
  mckayChi1EqualsClinamen,
  tritonRotation,
  tritonRotationOrderThree,
  tritonRotationVisitsAllThree,
  tritonStretch,
  tritonStretchIsMultiplicativeRotation,
} from '../src/pleromatic-monster-mesh';

describe('McKay constants', () => {
  it('chi1 = 1', () => {
    expect(MCKAY_CHI1).toBe(1);
  });

  it('chi2 = 196883', () => {
    expect(MCKAY_CHI2).toBe(196883);
  });

  it('chi3 = 21296876', () => {
    expect(MCKAY_CHI3).toBe(21296876);
  });

  it('c1 = 196884', () => {
    expect(MCKAY_C1).toBe(196884);
  });

  it('c2 = 21493760', () => {
    expect(MCKAY_C2).toBe(21493760);
  });
});

describe('McKay decompositions', () => {
  it('mckayC1Decomposition: c1 = chi1 + chi2', () => {
    expect(mckayC1Decomposition()).toBe(true);
  });

  it('mckayC2Decomposition: c2 = chi1 + chi2 + chi3', () => {
    expect(mckayC2Decomposition()).toBe(true);
  });

  it('clinamenAtC1 = 1', () => {
    expect(clinamenAtC1()).toBe(1);
  });

  it('clinamenAtC2 = 1', () => {
    expect(clinamenAtC2()).toBe(1);
  });
});

describe('Triton rotation (order 3)', () => {
  it('TRITON_ROTATION_ORDER = 3', () => {
    expect(TRITON_ROTATION_ORDER).toBe(3);
  });

  it('tritonRotation(0) = 1', () => {
    expect(tritonRotation(0)).toBe(1);
  });

  it('tritonRotation(1) = 2', () => {
    expect(tritonRotation(1)).toBe(2);
  });

  it('tritonRotation(2) = 0', () => {
    expect(tritonRotation(2)).toBe(0);
  });

  it('tritonRotationOrderThree(0) = true', () => {
    expect(tritonRotationOrderThree(0)).toBe(true);
  });

  it('tritonRotationOrderThree(1) = true', () => {
    expect(tritonRotationOrderThree(1)).toBe(true);
  });

  it('tritonRotationOrderThree(2) = true', () => {
    expect(tritonRotationOrderThree(2)).toBe(true);
  });

  it('tritonRotationVisitsAllThree = true', () => {
    expect(tritonRotationVisitsAllThree()).toBe(true);
  });
});

describe('Triton stretch (multiplicative form)', () => {
  it('tritonStretch(k) = 3k', () => {
    expect(tritonStretch(0)).toBe(0);
    expect(tritonStretch(1)).toBe(3);
    expect(tritonStretch(10)).toBe(30);
    expect(tritonStretch(30)).toBe(90);
  });

  it('tritonStretchIsMultiplicativeRotation holds at sample points', () => {
    for (const k of [0, 1, 2, 5, 10, 30, 100]) {
      expect(tritonStretchIsMultiplicativeRotation(k)).toBe(true);
    }
  });
});

describe('Constructive interference (Bizarro Noise)', () => {
  it.each([0, 5, 10, 30])(
    'forkChildrenConstructiveInterference(%i): all fold to k, children = [3k, 3k+1, 3k+2]',
    (k) => {
      const result = forkChildrenConstructiveInterference(k);
      expect(result.allFoldToK).toBe(true);
      expect(result.children).toEqual([3 * k, 3 * k + 1, 3 * k + 2]);
    },
  );

  it.each([0, 1, 5, 10, 30, 100])(
    'interferencePatternIsPureCoincidence(%i) = true',
    (k) => {
      expect(interferencePatternIsPureCoincidence(k)).toBe(true);
    },
  );
});

describe('Shared unit identity (the bridge)', () => {
  it('mckayChi1EqualsClinamen = true', () => {
    expect(mckayChi1EqualsClinamen()).toBe(true);
  });

  it('clinamenAppearsInMckayC1 = true', () => {
    expect(clinamenAppearsInMckayC1()).toBe(true);
  });
});

describe('PleromaticMonsterMeshMaster', () => {
  it('Triton rotation has order 3 on {0, 1, 2}', () => {
    expect(PleromaticMonsterMeshMaster.tritonRotationOrderThreeOnAll).toBe(
      true,
    );
  });

  it('McKay chi1 = 1', () => {
    expect(PleromaticMonsterMeshMaster.mckayChi1IsOne).toBe(true);
  });

  it('c1 decomposition holds', () => {
    expect(PleromaticMonsterMeshMaster.c1Decomposition).toBe(true);
  });

  it('clinamen at c1 equals chi1', () => {
    expect(PleromaticMonsterMeshMaster.clinamenAtC1).toBe(true);
  });

  it('fork-children interference samples for k = 0, 5, 10, 30', () => {
    const samples = PleromaticMonsterMeshMaster.forkChildrenInterferenceSamples;
    expect(samples).toHaveLength(4);
    expect(samples.map((s) => s.k)).toEqual([0, 5, 10, 30]);
    for (const sample of samples) {
      expect(sample.allFoldToK).toBe(true);
      expect(sample.children).toEqual([
        3 * sample.k,
        3 * sample.k + 1,
        3 * sample.k + 2,
      ]);
    }
  });

  it('all expected master witnesses are present', () => {
    expect(PleromaticMonsterMeshMaster).toHaveProperty(
      'tritonRotationOrderThreeOnAll',
    );
    expect(PleromaticMonsterMeshMaster).toHaveProperty('mckayChi1IsOne');
    expect(PleromaticMonsterMeshMaster).toHaveProperty('c1Decomposition');
    expect(PleromaticMonsterMeshMaster).toHaveProperty('clinamenAtC1');
    expect(PleromaticMonsterMeshMaster).toHaveProperty(
      'forkChildrenInterferenceSamples',
    );
  });
});
